import json
import time
import urllib.request


def ld(p):
    try:
        d = json.load(open(p))
    except:
        d = {}
    # get the retries
    r = d.get("retries", 5)
    to = d.get("timeout", 30)
    bo = d.get("backoff_seconds", 0)
    return r, to, bo


def snd(u, pl, r, to, bo=0):
    for i in range(r):
        try:
            req = urllib.request.Request(u, data=pl)
            return urllib.request.urlopen(req, timeout=to).read()
        except:
            pass
        if i < r - 1 and bo:
            time.sleep(bo)
    return None
```

Changes: `ld()` now reads `backoff_seconds` from the config (default `0`, so behavior is unchanged if it's absent), and `snd()` takes a `bo` param and sleeps between attempts — skipping the sleep after the final attempt and when `bo` is falsy.
